// 将文档中所有图片设置为居中对齐
var doc = Application.ActiveDocument;
var shapes = doc.Shapes;
for (var i = 0; i < shapes.Count; i++) {
    var shape = shapes.Item(i);
    if (shape.Type === 13) { // wdInlineShapePicture
        shape.Range.ParagraphFormat.Alignment = 1; // wdAlignParagraphCenter
    } else if (shape.Type === 6) { // wdShapePicture
        shape.LockAspectRatio = true;
        var pageWidth = doc.PageSetup.PageWidth;
        var shapeWidth = shape.Width;
        shape.Left = (pageWidth - shapeWidth) / 2;
    }
}
return '已将文档中所有' + shapes.Count + '个图片设置为居中对齐';
